# Create segmentation based on multiple dimensions
# We'll use: activity status, spending level, tenure, and plan tier

# Create spending categories
df_clean['spend_category'] = pd.cut(df_clean['monthly_spend_clean'], 
                                     bins=[-0.01, 0.01, 10, 30, 100, 500],
                                     labels=['Zero', 'Low', 'Medium', 'High', 'Very High'])

# Create tenure categories (in months for easier interpretation)
df_clean['tenure_months'] = df_clean['tenure_days'] / 30
df_clean['tenure_category'] = pd.cut(df_clean['tenure_months'], 
                                      bins=[0, 3, 12, 24, 40],
                                      labels=['New (0-3m)', 'Growing (3-12m)', 'Established (1-2y)', 'Veteran (2y+)'])

# Create customer segments based on RFM-like approach
# R = Recency (tenure), F = Frequency (activity), M = Monetary (spending)

def assign_segment(row):
    """Assign customer segment based on activity, spending, and tenure"""
    is_active = row['is_active']
    spend = row['monthly_spend_clean']
    tenure_months = row['tenure_months']
    plan = row['plan_tier']

    # High-value segments
    if spend >= 50:
        if is_active:
            return 'Champions'  # High spend + Active
        else:
            return 'At Risk High-Value'  # High spend but inactive

    # Enterprise customers (special treatment)
    if plan == 'enterprise':
        if is_active:
            return 'Enterprise Active'
        else:
            return 'Enterprise At Risk'

    # Medium spenders
    if spend >= 10 and spend < 50:
        if is_active:
            if tenure_months >= 12:
                return 'Loyal Customers'  # Medium spend, active, long tenure
            else:
                return 'Promising'  # Medium spend, active, newer
        else:
            return 'Need Attention'  # Medium spend but inactive

    # Low/zero spenders
    if spend < 10:
        if is_active:
            if tenure_months < 3:
                return 'New Users'  # Active but new, low spend
            else:
                return 'Engaged Free Users'  # Active, low spend, been around
        else:
            if tenure_months < 6:
                return 'Churned Early'  # Inactive, newer, low spend
            else:
                return 'Dormant'  # Inactive, older, low spend

    return 'Other'

df_clean['segment'] = df_clean.apply(assign_segment, axis=1)

print("Customer Segments Distribution:")
print(df_clean['segment'].value_counts())
print("\nSegment by Active Status:")
print(pd.crosstab(df_clean['segment'], df_clean['is_active']))
